import React from 'react';
import Main from './components/Main';
import Portfolio from './components/Portfolio';
import Contact from './components/Contact';
import About from './components/About';


class App extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      page: 'main'
    }
  }

  handleClick = (e) => {
    const screen = e.target.id;
    this.setState({
      page: screen
    })
  }

  render() {
    let isMain = false;
    if (this.state.page === "main" || this.state.page === "main-1" || this.state.page === "main-2" || this.state.page === "main-3") {
      isMain = true;
    } else {
      isMain = false;
    }
    return(
      <main id="app">
      {isMain && <Main handleClick={this.handleClick} />}
      {this.state.page === "about-me" && <About handleClick={this.handleClick} />}
      {this.state.page === "portfolio" && <Portfolio handleClick={this.handleClick} />}
      {this.state.page === "contact" && <Contact handleClick={this.handleClick} />}
      </main>
    )
}
}

export default App;
