import React from 'react';
import propTypes from 'prop-types';
import {Accordion, Card} from 'react-bootstrap';


class About extends React.Component {
    constructor(props) {
        super(props);
        this.state = {
            p1: true,
            p2: false,
            p3: false
        }
    }

    oneClick = () => {
        const open = this.state.p1;
        open
            ? this.setState({
                p1: false,
                p2: false,
                p3: false
            })
            : this.setState({
                p1: true,
                p2: false,
                p3: false
            })
    }

    twoClick = () => {
        const open = this.state.p2;
        open
            ? this.setState({
                p1: false,
                p2: false,
                p3: false
            })
            : this.setState({
                p1: false,
                p2: true,
                p3: false
            })
    }

    threeClick = () => {
        const open = this.state.p3;
        open
            ? this.setState({
                p1: false,
                p2: false,
                p3: false
            })
            : this.setState({
                p1: false,
                p2: false,
                p3: true
            })
    }

    render() {
        return (
            <div id="about-page">
                <header id="about-title-card">
                    <div id="about-back">
                        <button type="button" id="main-1" className="back" onClick={this.props.handleClick}><i className="fas fa-angle-left"></i> Menu</button>
                    </div>
                    <h1 id="about-title">About Me</h1>
                </header>
                <div id="about-main-card">
                    <Accordion defaultActiveKey="0" id="about-text">

                        <Card className="about-card shadow">
                            <Accordion.Toggle as={Card.Header} eventKey="0" className="about-header" onClick={this.oneClick}>
                                <h2>Front End Developer | Writer | Doer</h2>
                                <button type="button">{this.state.p1 ? "-" : "+"}</button>
                            </Accordion.Toggle>
                            <Accordion.Collapse eventKey="0">
                            <Card.Body className="about-paragraph">
                                <p>No matter what your web development need is, I'm your expert. With certifications covering the full spectrum of essential and current front end technologies, I am prepared to tackle every step of your web development process, from designing wireframes, to interacting with APIs, to fully implementing and debugging efficient, beautiful code. And with a BA and extensive writing experience in my toolbox, I can handle your creative needs as well. The bottom line: I am a front end warrior, indefatigable in my ability to overcome any problem to produce the best work possible.</p>
                            </Card.Body>
                            </Accordion.Collapse>
                        </Card>

                        <Card id="card-2" className="shadow">
                            <Accordion.Toggle as={Card.Header} eventKey="1" className="about-header" onClick={this.twoClick}>
                                <h2>Fast Facts...</h2>
                                <button type="button">{this.state.p2 ? "-" : "+"}</button>
                            </Accordion.Toggle>

                            <Accordion.Collapse eventKey="1">
                                <Card.Body className="about-paragraph">
                                <ul>
                                    <li>I have certifications in Responsive Web Design, JavaScript Algorithms and Data Structures, and Front End Libraries.</li>
                                    <li>I am experienced in HTML, CSS, JavaScript, React, Redux, Bootstrap, jQuery, SASS, Git, and Node.</li>
                                    <li>I have a BA in Liberal Arts with a minor in English from Colorado State University, where I was nominated as a University Honors Scholar.</li>
                                    <li>My work is carefully attentive to both responsive design principles and accessibility.</li>
                                </ul>
                                </Card.Body>
                            </Accordion.Collapse>
                        </Card>

                        <Card className="shadow">
                            <Accordion.Toggle as={Card.Header} eventKey="2" className="about-header" onClick={this.threeClick}>
                                <h2>Got your attention?</h2>
                                <button type="button" >{this.state.p3 ? "-" : "+"}</button>
                            </Accordion.Toggle>
                            <Accordion.Collapse eventKey="2">
                            <Card.Body className="about-paragraph">
                                <p>Check out some of my work on the Portfolio page. Or, if you want a more detailed breakdown of my experience, download my Resume. If you think we'd be a good fit, you can find a way to reach me on the Contact page.</p>
                            </Card.Body>
                            </Accordion.Collapse>
                            




                        </Card>

                    </Accordion>

                </div>



            </div>
        )
    }
}

About.propTypes = { handleClick: propTypes.func.isRequired };

export default About;
