import React, { Component } from 'react';
import calculator from '../static assets/calculator.png';
import drum from '../static assets/drum.png';
import quote from '../static assets/quote.png';
import markdown from '../static assets/markdown.png';
import clock from '../static assets/clock.png';
import landing from '../static assets/landing.png';
import propTypes from 'prop-types';

class Portfolio extends Component {
    render() {
        return (
            <div id="portfolio-page">
                <div id="portfolio-main-card">
                    
                    <nav id="project-grid">
                        <a href="http://austin-knauer.github.io/drum-machine" target="_blank" className="card shadow" id="drum">
                            <img src={drum} alt="drum machine preview" className="card-img-top"></img>
                            <div className="card-body">
                                <h2 className="card-title">Drum Machine</h2>
                                <h3 className="card-subtitle">React, Bootstrap</h3>
                                <p className="card-text"><i className="fas fa-desktop"></i> <i className="far fa-object-group"></i></p>
                            </div>

                        </a>
                        <a href="http://austin-knauer.github.io/random-quote" target="_blank" className="card shadow" id="quote">
                            <img src={quote} alt="random quote preview" className="card-img-top"></img>
                            <div className="card-body">
                                <h2 className="card-title">Random Quote Machine</h2>
                                <h3 className="card-subtitle">jQuery, Bootstrap</h3>
                                <p className="card-text"><i className="fas fa-desktop"></i> <i className="far fa-object-group"></i></p>
                            </div>

                        </a>
                        <a href="http://austin-knauer.github.io/markdown-previewer" target="_blank" className="card shadow" id="markdown">
                            <img src={markdown} alt="markdown previewer preview" className="card-img-top"></img>
                            <div className="card-body">
                                <h2 className="card-title">Markdown Previewer</h2>
                                <h3 className="card-subtitle">React</h3>
                                <p className="card-text"><i className="fas fa-desktop"></i> <i className="far fa-object-group"></i></p>
                            </div>
                        </a>
                        <a href="http://austin-knauer.github.io/calculator" target="_blank" className="card shadow" id="calculator">
                            <img src={calculator} alt="calculator preview" className="card-img-top"></img>
                            <div className="card-body">
                                <h2 className="card-title">JavaScript Calculator</h2>
                                <h3 className="card-subtitle">React, Redux, Sass</h3>
                                <p className="card-text"><i className="fas fa-arrows-alt-h"></i> <i className="far fa-object-group"></i></p>
                            </div>

                        </a>
                        <a href="http://austin-knauer.github.io/clock" target="_blank" className="card shadow" id="clock">
                            <img src={clock} alt="clock preview" className="card-img-top"></img>
                            <div className="card-body">
                                <h2 className="card-title">Productivity Clock</h2>
                                <h3 className="card-subtitle">React, Sass, Bootstrap</h3>
                                <p className="card-text"><i className="fas fa-mobile-alt"></i> <i className="far fa-object-group"></i></p>
                            </div>

                        </a>
                        <a href="http://austin-knauer.github.io/product-landing" target="_blank" className="card shadow" id="landing">
                            <img src={landing} alt="product landing preview" className="card-img-top"></img>
                            <div className="card-body">
                                <h2 className="card-title">Product Landing Page</h2>
                                <p className="card-text"><i className="fas fa-desktop"></i> <i className="far fa-object-group"></i></p>
                            </div>
                        </a>
                    </nav>
                    <div id="key" className="shadow">
                        <h2 className="card-title mr-2">Key</h2>
                        <p className="key-icon key-item"><i className="fas fa-desktop"></i></p>
                        <p className="key-item">Designed <br />for Desktop</p>
                        <p className="key-icon key-item"><i className="fas fa-mobile-alt"></i></p>
                        <p className="key-item">Designed <br />for Mobile</p>
                        <p className="key-icon key-item"><i className="fas fa-arrows-alt-h"></i></p>
                        
                        <p className="key-item">Designed <br />for Either</p>
                        <p className="key-icon key-item"><i className="far fa-object-group"></i></p>
                        <p className="key-item" id="last-key">Responsively <br />Designed</p>

                    </div>


                </div>


                <header id="portfolio-title-card">
                    <h1 id="portfolio-title">Port<wbr></wbr>folio</h1>
                    <div id="portfolio-back">
                        <button type="button" id="main-2" className="back" onClick={this.props.handleClick}><i className="fas fa-angle-right"></i> &nbsp;Menu</button>
                    </div>
                </header>
            </div>
        )
    }
}

Portfolio.propTypes = {handleClick: propTypes.func.isRequired};

export default Portfolio
