import React, { Component } from 'react';
import propTypes from 'prop-types';
import resume from '../static assets/Austin Knauer F.pdf';

class Main extends Component {
    render() {
        return (
            <div id="main-page">
                <header id="name-card">
                    <h1 id="name-title">AUSTIN<br />KNAUER</h1>
                </header>
                <nav id="button-card">
                    <button type="button" id="about-me" className="links" onClick={this.props.handleClick}>About Me</button>
                    <button type="button" id="portfolio" className="links" onClick={this.props.handleClick}>Portfolio</button>
                    <button type="button" id="contact" className="links" onClick={this.props.handleClick}>Contact</button>
                    <a href={resume} download="Austin Knauer Resume" className="links" id="resume">Resume</a>
                </nav>
            </div>
        )
    }
}

Main.propTypes = {handleClick: propTypes.func.isRequired};

export default Main
